TSP问题 Tsp问题是指旅行家要旅行n个城市，要求各个城市经历且经历一次，然后回到出发城市，并要求所走路线最短。
蛮力法求TSP问题 使用深度优先遍历求出所有可能的路径，然后找到最短的。
#include &lt;iostream&gt; #define N 100 using namespace std; bool visited[N]; int arc[N][N]; int path[N]; int min_path[N]; int depth = 0; int minlength = 65536; void DFS(int v, int n) { if (depth == n) { int temp = 0; for (int i = 0; i &lt; n - 1; i++) { temp += arc[path[i]][path[i + 1]]; } temp += arc[path[0]][path[n - 1]]; if (temp &lt; minlength) { minlength = temp; for (int i = 0; i &lt; n; i++) { min_path[i] = path[i]; } } } for (int i = 0; i &lt; n; i++) { if (arc[v][i] !
